class Solution {
    public int countKReducibleNumbers(String s, int k) {
        int result = 0;
        int num = Integer.parseInt(s);
        int mask = 1 << k;

        for (int i = num; i >= 1; i--) {
            int count = 0;
            while (i % mask == 0) {
                count++;
                i >>= k;
            }
            result += count;
        }

        return result % (1000000007);
    }
}
```

